        using T = std::vector&lt;sn::example::Record&gt;;
        auto data = h5::read&lt;T&gt;(fd,"/orm/partial/vector one_shot");
        std::cerr &lt;&lt;"reading back data previously written:\n\t";
        for( auto r:data )
            std::cerr &lt;&lt; r.idx &lt;&lt;" ";
        std::cerr &lt;&lt; std::endl;
    }
